// mascotte.jsx — "Pluis" als herbruikbare VECTOR-component (geen PNG meer).
// Vlakke 2D-stijl, hand-drawn wiebellijn, gedeeld lichaam + gezicht ZONDER NEUS.
// Per categorie een eigen attribuut + armhouding. Exporteert window.Mascotte.
//
//   <Mascotte categorie="denk" pose="c" size={220} />
//
// categorie: creatief | beweeg | denk | ontdek | muziek | koken | samen
// pose: "c" | "d" (ook 2/3). "d" spiegelt voor variatie. Default: willekeurig.

(function () {
  const INKT = "#1A1A1A";
  const GEEL = "#FBC42E";
  const ROZE = "#F79FD0";
  const ROZE_L = "#FCD6EC";
  const BLUSH = "#F58BB0";
  const HOUT = "#F2D2A0";
  const WIT = "#FFFFFF";

  const L = { fill: "none", stroke: INKT, strokeWidth: 7, strokeLinecap: "round", strokeLinejoin: "round" };
  const L5 = { ...L, strokeWidth: 6 };

  // ── Gedeeld lichaam (gele blob met geschulpte onderkant), gecentreerd ~x310 ──
  const BODY_D =
    "M 198,430 C 190,300 230,172 312,170 C 398,168 438,300 430,432 " +
    "L 430,548 C 430,605 373,605 373,550 C 373,605 316,605 316,550 " +
    "C 316,605 259,605 259,550 C 259,600 202,600 202,548 " +
    "C 200,500 196,470 198,430 Z";

  function Body() {
    return <path d={BODY_D} fill={GEEL} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />;
  }

  // Gezicht — ZONDER neus. eyesClosed voor de muziek-pose.
  function Face({ eyesClosed }) {
    return (
      <g>
        {eyesClosed ? (
          <g>
            <path style={L5} d="M 264,300 C 272,310 290,310 298,300" />
            <path style={L5} d="M 320,300 C 328,310 346,310 354,300" />
          </g>
        ) : (
          <g>
            <ellipse cx="285" cy="302" rx="14" ry="19" fill={INKT} />
            <ellipse cx="335" cy="302" rx="14" ry="19" fill={INKT} />
            <circle cx="280" cy="294" r="5" fill={WIT} />
            <circle cx="330" cy="294" r="5" fill={WIT} />
            <path style={L5} d="M 266,272 C 276,265 296,266 304,274" />
            <path style={L5} d="M 316,274 C 324,266 344,265 354,272" />
          </g>
        )}
        {/* glimlach (geen neus erboven) */}
        <path style={L5} d="M 296,344 C 305,357 315,357 324,344" />
        {/* blos */}
        <ellipse cx="368" cy="332" rx="15" ry="9" fill={BLUSH} opacity="0.85" />
        <ellipse cx="252" cy="332" rx="14" ry="8" fill={BLUSH} opacity="0.5" />
      </g>
    );
  }

  function DefaultLegs() {
    return (
      <g>
        <path style={L} d="M 285,592 C 281,640 279,678 281,706 L 263,714" />
        <path style={L} d="M 337,592 C 337,642 337,680 335,702 L 353,710" />
      </g>
    );
  }

  // Hangende arm rechts (scherm-rechts) met bolletjeshand
  function ArmRight() {
    return (
      <g>
        <path style={L} d="M 423,402 C 482,415 492,495 457,540 C 451,550 445,554 440,555" />
        <circle cx="440" cy="555" r="9" fill={INKT} />
      </g>
    );
  }
  function ArmLeft() {
    return (
      <g>
        <path style={L} d="M 197,402 C 138,415 128,495 163,540 C 169,550 175,554 180,555" />
        <circle cx="180" cy="555" r="9" fill={INKT} />
      </g>
    );
  }

  // ── Per-categorie poses ─────────────────────────────────────────────
  function PoseCreatief() {
    return (
      <g>
        <Body />
        <DefaultLegs />
        <ArmRight />
        {/* potlood, diagonaal voor het lijf */}
        <path d="M 124,224 L 176,196 L 326,481 L 274,509 Z" fill={ROZE} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />
        <path d="M 150,210 L 296,488" stroke={WIT} strokeWidth="6" strokeLinecap="round" opacity="0.5" fill="none" />
        {/* gum / witte band boven */}
        <path d="M 124,224 L 176,196 L 160,168 L 108,196 Z" fill={WIT} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />
        {/* houten punt */}
        <path d="M 274,509 L 326,481 L 316,540 Z" fill={HOUT} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />
        {/* grafiet tip */}
        <path d="M 300,520 L 316,540 L 322,514 Z" fill={INKT} />
        {/* linkerhand grijpt potlood + hartje-duim */}
        <path style={L} d="M 205,470 C 178,442 196,378 216,362" />
        <path d="M 206,376 C 192,378 190,360 204,355 C 215,351 230,360 224,376 C 233,386 214,398 206,376 Z" fill={INKT} stroke={INKT} strokeWidth="4" strokeLinejoin="round" />
        <path d="M 214,348 C 209,341 199,342 200,351 C 201,357 209,361 214,366 C 219,361 227,357 228,351 C 229,342 219,341 214,348 Z" fill={INKT} />
      </g>
    );
  }

  function PoseDenk() {
    return (
      <g>
        {/* denkwolk rechtsboven met ? */}
        <g>
          <circle cx="430" cy="248" r="10" fill={WIT} stroke={INKT} strokeWidth="5" />
          <circle cx="452" cy="214" r="15" fill={WIT} stroke={INKT} strokeWidth="5" />
          <ellipse cx="500" cy="150" rx="58" ry="46" fill={WIT} stroke={INKT} strokeWidth="6" />
          <text x="500" y="168" textAnchor="middle" fontFamily="Bricolage Grotesque, sans-serif" fontWeight="800" fontSize="56" fill={INKT}>?</text>
        </g>
        <Body />
        <DefaultLegs />
        <ArmLeft />
        {/* rechterhand naar de kin */}
        <path style={L} d="M 425,412 C 460,430 412,392 360,372" />
        <circle cx="356" cy="370" r="10" fill={INKT} />
      </g>
    );
  }

  function PoseBeweeg() {
    return (
      <g>
        {/* vaartlijntjes */}
        <g stroke={ROZE} strokeWidth="7" strokeLinecap="round">
          <line x1="120" y1="470" x2="190" y2="470" />
          <line x1="105" y1="505" x2="178" y2="505" />
          <line x1="120" y1="540" x2="190" y2="540" />
        </g>
        <g transform="rotate(-7 312 400)">
          <Body />
          {/* rennende benen */}
          <path style={L} d="M 300,590 C 282,624 268,650 250,662 L 258,680" />
          <path style={L} d="M 348,588 C 366,608 392,612 408,628 L 424,622" />
          <Face eyesClosed={false} />
          {/* gebogen armen */}
          <path style={L} d="M 425,405 C 458,392 466,425 452,452" />
          <circle cx="450" cy="455" r="8" fill={INKT} />
          <path style={L} d="M 200,408 C 168,398 158,430 172,455" />
          <circle cx="173" cy="457" r="8" fill={INKT} />
        </g>
      </g>
    );
  }

  function PoseOntdek() {
    return (
      <g>
        <Body />
        <DefaultLegs />
        <ArmRight />
        {/* vergrootglas in linkerhand, omhoog bij gezicht */}
        <path style={L} d="M 205,460 C 180,430 160,392 150,360" />
        <circle cx="150" cy="300" r="40" fill={ROZE_L} stroke={ROZE} strokeWidth="12" />
        <circle cx="150" cy="300" r="40" fill="none" stroke={INKT} strokeWidth="5" />
        <circle cx="150" cy="300" r="28" fill="none" stroke={INKT} strokeWidth="4" opacity="0.4" />
        <path d="M 130,338 L 112,360" stroke={ROZE} strokeWidth="16" strokeLinecap="round" fill="none" />
        <path d="M 130,338 L 112,360" stroke={INKT} strokeWidth="5" strokeLinecap="round" fill="none" />
        {/* handje rond steel */}
        <circle cx="150" cy="356" r="11" fill={INKT} />
      </g>
    );
  }

  function PoseMuziek() {
    return (
      <g>
        {/* muzieknoot */}
        <g>
          <ellipse cx="452" cy="232" rx="14" ry="11" fill={INKT} transform="rotate(-18 452 232)" />
          <path d="M 465,228 L 465,168" stroke={INKT} strokeWidth="6" strokeLinecap="round" />
          <path d="M 465,168 C 482,172 486,186 484,198" stroke={INKT} strokeWidth="6" strokeLinecap="round" fill="none" />
        </g>
        <Body />
        <DefaultLegs />
        <ArmLeft />
        <ArmRight />
        <Face eyesClosed={true} />
        {/* koptelefoon: beugel + oorschelpen */}
        <path d="M 228,278 C 236,178 388,178 396,278" fill="none" stroke={INKT} strokeWidth="11" strokeLinecap="round" />
        <rect x="208" y="262" width="36" height="64" rx="16" fill={ROZE} stroke={INKT} strokeWidth="6" />
        <rect x="380" y="262" width="36" height="64" rx="16" fill={ROZE} stroke={INKT} strokeWidth="6" />
      </g>
    );
  }

  function PoseKoken() {
    return (
      <g>
        <Body />
        <DefaultLegs />
        {/* koksmuts */}
        <rect x="262" y="176" width="100" height="26" rx="8" fill={WIT} stroke={INKT} strokeWidth="6" />
        <path d="M 268,180 C 250,150 268,120 296,128 C 300,104 348,104 352,128 C 380,120 396,150 378,180 Z" fill={WIT} stroke={INKT} strokeWidth="6" strokeLinejoin="round" />
        <Face eyesClosed={false} />
        {/* mengkom vooraan */}
        <path d="M 244,500 C 244,572 380,572 380,500 Z" fill={ROZE} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />
        <ellipse cx="312" cy="500" rx="68" ry="16" fill={ROZE_L} stroke={INKT} strokeWidth="7" />
        {/* garde in rechterhand */}
        <path style={L} d="M 425,412 C 446,418 446,442 436,456" />
        <path d="M 432,452 L 388,506" stroke={INKT} strokeWidth="7" strokeLinecap="round" fill="none" />
        <g fill="none" stroke={INKT} strokeWidth="4">
          <path d="M 388,506 C 372,494 372,476 384,470" />
          <path d="M 388,506 C 380,486 386,472 398,468" />
          <path d="M 388,506 C 392,484 404,476 410,476" />
        </g>
        {/* linkerhand aan de rand */}
        <path style={L} d="M 200,460 C 200,492 218,498 240,498" />
        <circle cx="244" cy="498" r="9" fill={INKT} />
      </g>
    );
  }

  function PoseSamen() {
    return (
      <g>
        <Body />
        <DefaultLegs />
        {/* hart vooraan, met beide handjes eromheen */}
        <path d="M 312,540 C 270,500 248,476 248,450 C 248,428 268,418 286,428 C 298,434 308,446 312,456 C 316,446 326,434 338,428 C 356,418 376,428 376,450 C 376,476 354,500 312,540 Z" fill={ROZE} stroke={INKT} strokeWidth="7" strokeLinejoin="round" />
        <path d="M 268,452 C 264,440 276,434 284,442" stroke={WIT} strokeWidth="6" strokeLinecap="round" fill="none" opacity="0.6" />
        <path style={L} d="M 205,440 C 220,478 244,490 262,492" />
        <circle cx="264" cy="492" r="10" fill={INKT} />
        <path style={L} d="M 419,440 C 404,478 380,490 362,492" />
        <circle cx="360" cy="492" r="10" fill={INKT} />
      </g>
    );
  }

  const POSES = {
    creatief: PoseCreatief,
    denk: PoseDenk,
    beweeg: PoseBeweeg,
    ontdek: PoseOntdek,
    muziek: PoseMuziek,
    koken: PoseKoken,
    samen: PoseSamen,
  };

  // Categorieën die het gezicht zelf binnen de pose tekenen (gewijzigd gezicht).
  const ZELF_GEZICHT = { beweeg: true, muziek: true, koken: true };

  // Eigen geleverde vector-illustraties (SVG), ingebakken als data-URI zodat
  // er geen losse beeldbestanden of mappen nodig zijn bij het hosten.
  const EXTERN = {
    creatief: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    beweeg: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    denk: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    ontdek: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    muziek: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    koken: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
    samen: { c: "data:image/svg+xml;base64,", d: "data:image/svg+xml;base64," },
  };

  function Mascotte({ categorie = "creatief", pose, size = 220, style = {} }) {
    // Eigen geleverde SVG-illustratie? Toon die rechtstreeks.
    const ext = EXTERN[categorie];
    if (ext) {
      const key = pose === "d" || pose === 3 || pose === 1 ? "d" : (pose === "c" || pose === 2 || pose === 0 ? "c" : (Math.random() < 0.5 ? "c" : "d"));
      const src = ext[key] || ext.c;
      return (
        <div style={{ width: size, height: size, display: "flex", alignItems: "center", justifyContent: "center", ...style }}>
          <img src={src} alt={`Pluis — ${categorie}`} style={{ maxWidth: "100%", maxHeight: "100%", objectFit: "contain", display: "block" }} />
        </div>
      );
    }

    const Pose = POSES[categorie] || PoseCreatief;
    const flip = pose === "d" || pose === 3;
    return (
      <div style={{ width: size, height: size, display: "flex", alignItems: "center", justifyContent: "center", ...style }}>
        <svg viewBox="80 90 460 650" style={{ width: "100%", height: "100%", overflow: "visible" }} role="img" aria-label={`Pluis — ${categorie}`}>
          <defs>
            <filter id="pluisRuw" x="-12%" y="-12%" width="124%" height="124%">
              <feTurbulence type="fractalNoise" baseFrequency="0.012" numOctaves="2" seed="5" result="n" />
              <feDisplacementMap in="SourceGraphic" in2="n" scale="3.5" xChannelSelector="R" yChannelSelector="G" />
            </filter>
          </defs>
          <g filter="url(#pluisRuw)" transform={flip ? "translate(620,0) scale(-1,1)" : undefined}>
            <Pose />
            {!ZELF_GEZICHT[categorie] && <Face eyesClosed={false} />}
          </g>
        </svg>
      </div>
    );
  }

  window.Mascotte = Mascotte;
})();
